  1→import type { NoiseAction, NoiseRule } from "./format-types.js";
  2→import { STATUS_ICONS, KIND_ICONS } from "./format-types.js";
  3→
  4→export function extractContentText(content: unknown, depth = 0): string {
  5→  if (!content || depth > 5) return "";
  6→  if (typeof content === "string") return content;
  7→  if (Array.isArray(content)) {
  8→    return content
  9→      .map((c) => extractContentText(c, depth + 1))
 10→      .filter(Boolean)
 11→      .join("\n");
 12→  }
 13→  if (typeof content !== "object") return String(content);
 14→
 15→  const obj = content as Record<string, unknown>;
 16→  if (obj.text && typeof obj.text === "string") return obj.text;
 17→  if (obj.content) {
 18→    if (typeof obj.content === "string") return obj.content;
 19→    if (Array.isArray(obj.content)) {
 20→      return obj.content
 21→        .map((c) => extractContentText(c, depth + 1))
 22→        .filter(Boolean)
 23→        .join("\n");
 24→    }
 25→    return extractContentText(obj.content, depth + 1);
 26→  }
 27→  if (obj.input) return extractContentText(obj.input, depth + 1);
 28→  if (obj.output) return extractContentText(obj.output, depth + 1);
 29→
 30→  // Skip objects with only a 'type' key and no content fields
 31→  const keys = Object.keys(obj).filter((k) => k !== "type");
 32→  if (keys.length === 0) return "";
 33→
 34→  // Fallback: serialize unrecognized objects so edge-case agent responses are not silently dropped
 35→  try {
 36→    return JSON.stringify(obj, null, 2);
 37→  } catch {
 38→    return "";
 39→  }
 40→}
 41→
 42→function parseRawInput(rawInput: unknown): Record<string, unknown> {
 43→  try {
 44→    if (typeof rawInput === "string") {
 45→      return JSON.parse(rawInput) as Record<string, unknown>;
 46→    }
 47→    if (typeof rawInput === "object" && rawInput !== null) {
 48→      return rawInput as Record<string, unknown>;
 49→    }
 50→  } catch {
 51→    // fall through
 52→  }
 53→  return {};
 54→}
 55→
 56→// --- Step 5: formatToolSummary with displaySummary override ---
 57→
 58→export function formatToolSummary(
 59→  name: string,
 60→  rawInput: unknown,
 61→  displaySummary?: string,
 62→): string {
 63→  if (displaySummary && typeof displaySummary === "string") {
 64→    return displaySummary;
 65→  }
 66→
 67→  const args = parseRawInput(rawInput);
 68→  const lowerName = name.toLowerCase();
 69→
 70→  if (lowerName === "read") {
 71→    const fp = args.file_path ?? args.filePath ?? "";
 72→    const limit = args.limit ? ` (${args.limit} lines)` : "";
 73→    return fp ? `📖 Read ${fp}${limit}` : `🔧 ${name}`;
 74→  }
 75→  if (lowerName === "edit") {
 76→    const fp = args.file_path ?? args.filePath ?? "";
 77→    return fp ? `✏️ Edit ${fp}` : `🔧 ${name}`;
 78→  }
 79→  if (lowerName === "write") {
 80→    const fp = args.file_path ?? args.filePath ?? "";
 81→    return fp ? `📝 Write ${fp}` : `🔧 ${name}`;
 82→  }
 83→  if (lowerName === "bash") {
 84→    const cmd = String(args.command ?? "").slice(0, 60);
 85→    return cmd ? `▶️ Run: ${cmd}` : `🔧 ${name}`;
 86→  }
 87→  if (lowerName === "grep") {
 88→    const pattern = args.pattern ?? "";
 89→    const path = args.path ?? "";
 90→    return pattern
 91→      ? `🔍 Grep "${pattern}"${path ? ` in ${path}` : ""}`
 92→      : `🔧 ${name}`;
 93→  }
 94→  if (lowerName === "glob") {
 95→    const pattern = args.pattern ?? "";
 96→    return pattern ? `🔍 Glob ${pattern}` : `🔧 ${name}`;
 97→  }
 98→  if (lowerName === "agent") {
 99→    const desc = String(args.description ?? "").slice(0, 60);
100→    return desc ? `🧠 Agent: ${desc}` : `🔧 ${name}`;
101→  }
102→  if (lowerName === "webfetch" || lowerName === "web_fetch") {
103→    const url = String(args.url ?? "").slice(0, 60);
104→    return url ? `🌐 Fetch ${url}` : `🔧 ${name}`;
105→  }
106→  if (lowerName === "websearch" || lowerName === "web_search") {
107→    const query = String(args.query ?? "").slice(0, 60);
108→    return query ? `🌐 Search "${query}"` : `🔧 ${name}`;
109→  }
110→
111→  return `🔧 ${name}`;
112→}
113→
114→// --- Step 6: formatToolTitle for low verbosity ---
115→
116→export function formatToolTitle(
117→  name: string,
118→  rawInput: unknown,
119→  displayTitle?: string,
120→): string {
121→  if (displayTitle && typeof displayTitle === "string") {
122→    return displayTitle;
123→  }
124→
125→  const args = parseRawInput(rawInput);
126→  const lowerName = name.toLowerCase();
