  1→import type { NoiseAction, NoiseRule } from "./format-types.js";
  2→import { STATUS_ICONS, KIND_ICONS } from "./format-types.js";
  3→
  4→export function extractContentText(content: unknown, depth = 0): string {
  5→  if (!content || depth > 5) return "";
  6→  if (typeof content === "string") return content;
  7→  if (Array.isArray(content)) {
  8→    return content
  9→      .map((c) => extractContentText(c, depth + 1))
 10→      .filter(Boolean)
 11→      .join("\n");
 12→  }
 13→  if (typeof content !== "object") return String(content);
 14→
 15→  const obj = content as Record<string, unknown>;
 16→  if (obj.text && typeof obj.text === "string") return obj.text;
 17→  if (obj.content) {
 18→    if (typeof obj.content === "string") return obj.content;
 19→    if (Array.isArray(obj.content)) {
 20→      return obj.content
 21→        .map((c) => extractContentText(c, depth + 1))
 22→        .filter(Boolean)
 23→        .join("\n");
 24→    }
 25→    return extractContentText(obj.content, depth + 1);
 26→  }
 27→  if (obj.input) return extractContentText(obj.input, depth + 1);
 28→  if (obj.output) return extractContentText(obj.output, depth + 1);
 29→
 30→  // Skip objects with only a 'type' key and no content fields
 31→  const keys = Object.keys(obj).filter((k) => k !== "type");
 32→  if (keys.length === 0) return "";
 33→
 34→  // Fallback: serialize unrecognized objects so edge-case agent responses are not silently dropped
 35→  try {
 36→    return JSON.stringify(obj, null, 2);
 37→  } catch {
 38→    return "";
 39→  }
 40→}
 41→
 42→function parseRawInput(rawInput: unknown): Record<string, unknown> {
 43→  try {
 44→    if (typeof rawInput === "string") {
 45→      return JSON.parse(rawInput) as Record<string, unknown>;
 46→    }
 47→    if (typeof rawInput === "object" && rawInput !== null) {
 48→      return rawInput as Record<string, unknown>;
 49→    }
 50→  } catch {
 51→    // fall through
 52→  }
 53→  return {};
 54→}
 55→
 56→// --- Step 5: formatToolSummary with displaySummary override ---
 57→
 58→export function formatToolSummary(
 59→  name: string,
 60→  rawInput: unknown,
 61→  displaySummary?: string,
 62→): string {
 63→  if (displaySummary && typeof displaySummary === "string") {
 64→    return displaySummary;
 65→  }
 66→
 67→  const args = parseRawInput(rawInput);
 68→  const lowerName = name.toLowerCase().replace(/[\s_-]+/g, "");
 69→
 70→  if (lowerName === "read" || lowerName === "readfile") {
 71→    const fp = args.file_path ?? args.filePath ?? "";
 72→    const limit = args.limit ? ` (${args.limit} lines)` : "";
 73→    return fp ? `📖 Read ${fp}${limit}` : `🔧 ${name}`;
 74→  }
 75→  if (lowerName === "edit" || lowerName === "editfile") {
 76→    const fp = args.file_path ?? args.filePath ?? "";
 77→    return fp ? `✏️ Edit ${fp}` : `🔧 ${name}`;
 78→  }
 79→  if (lowerName === "write" || lowerName === "writefile") {
 80→    const fp = args.file_path ?? args.filePath ?? "";
 81→    return fp ? `📝 Write ${fp}` : `🔧 ${name}`;
 82→  }
 83→  if (
 84→    lowerName === "bash" ||
 85→    lowerName === "execute" ||
 86→    lowerName === "shell"
 87→  ) {
 88→    const cmd = String(args.command ?? "").slice(0, 60);
 89→    return cmd ? `▶️ Run: ${cmd}` : `🔧 ${name}`;
 90→  }
 91→  if (lowerName === "grep") {
 92→    const pattern = args.pattern ?? "";
 93→    const path = args.path ?? "";
 94→    return pattern
 95→      ? `🔍 Grep "${pattern}"${path ? ` in ${path}` : ""}`
 96→      : `🔧 ${name}`;
 97→  }
 98→  if (lowerName === "glob") {
 99→    const pattern = args.pattern ?? "";
100→    return pattern ? `🔍 Glob ${pattern}` : `🔧 ${name}`;
101→  }
102→  if (lowerName === "agent" || lowerName === "task") {
103→    const desc = String(args.description ?? args.prompt ?? "").slice(0, 60);
104→    return desc ? `🧠 Agent: ${desc}` : `🔧 ${name}`;
105→  }
106→  if (lowerName === "webfetch" || lowerName === "web_fetch") {
107→    const url = String(args.url ?? "").slice(0, 60);
108→    return url ? `🌐 Fetch ${url}` : `🔧 ${name}`;
109→  }
110→  if (lowerName === "websearch" || lowerName === "web_search") {
111→    const query = String(args.query ?? "").slice(0, 60);
112→    return query ? `🌐 Search "${query}"` : `🔧 ${name}`;
113→  }
114→
115→  return `🔧 ${name}`;
116→}
117→
118→// --- Step 6: formatToolTitle for low verbosity ---
119→
120→export function formatToolTitle(
121→  name: string,
122→  rawInput: unknown,
123→  displayTitle?: string,
124→): string {
125→  if (displayTitle && typeof displayTitle === "string") {
126→    return displayTitle;
127→  }
128→
129→  const args = parseRawInput(rawInput);
130→  const lowerName = name.toLowerCase().replace(/[\s_-]+/g, "");
131→
132→  if (
133→    ["read", "readfile", "edit", "editfile", "write", "writefile"].includes(
134→      lowerName,
135→    )
136→  ) {
137→    return String(args.file_path ?? args.filePath ?? name);
138→  }
139→  if (["bash", "execute", "shell"].includes(lowerName)) {
140→    return String(args.command ?? name).slice(0, 60);
141→  }
142→  if (lowerName === "grep") {
143→    const pattern = args.pattern ?? "";
144→    const path = args.path ?? "";
145→    return pattern ? `"${pattern}"${path ? ` in ${path}` : ""}` : name;
146→  }
147→  if (lowerName === "glob") {
148→    return String(args.pattern ?? name);
149→  }
150→  if (lowerName === "agent" || lowerName === "task") {
151→    return String(args.description ?? args.prompt ?? name).slice(0, 60);
152→  }
153→  if (["webfetch", "web_fetch"].includes(lowerName)) {
154→    return String(args.url ?? name).slice(0, 60);
155→  }
156→  if (["websearch", "web_search"].includes(lowerName)) {
157→    return String(args.query ?? name).slice(0, 60);
158→  }
159→
160→  return name;
161→}
162→
163→// --- Step 7: Noise filtering ---
164→
165→const NOISE_RULES: NoiseRule[] = [
166→  {
167→    match: (name) => name.toLowerCase() === "ls",
168→    action: "hide",
169→  },
170→  {
171→    match: (_name, kind, rawInput) => {
172→      if (kind !== "read") return false;
173→      const args = parseRawInput(rawInput);
174→      const p = String(args.file_path ?? args.filePath ?? args.path ?? "");
175→      return p.endsWith("/");
176→    },
177→    action: "hide",
178→  },
179→  {
180→    match: (name) => name.toLowerCase() === "glob",
181→    action: "collapse",
182→  },
183→];
184→
185→export function evaluateNoise(
186→  name: string,
187→  kind: string,
188→  rawInput: unknown,
189→): NoiseAction | null {
190→  for (const rule of NOISE_RULES) {
191→    if (rule.match(name, kind, rawInput)) return rule.action;
192→  }
193→  return null;
194→}
