217→export class ConfigManager extends EventEmitter {
218→  private config!: Config;
219→  private configPath: string;
220→
221→  constructor() {
222→    super();
223→    this.configPath =
224→      process.env.OPENACP_CONFIG_PATH || expandHome("~/.openacp/config.json");
225→  }
226→
227→  async load(): Promise<void> {
228→    // 1. Ensure directory exists
229→    const dir = path.dirname(this.configPath);
230→    fs.mkdirSync(dir, { recursive: true });
231→
232→    // 2. If config file doesn't exist, create default
233→    if (!fs.existsSync(this.configPath)) {
234→      fs.writeFileSync(
235→        this.configPath,
236→        JSON.stringify(DEFAULT_CONFIG, null, 2),
237→      );
238→      log.info({ configPath: this.configPath }, "Config created");
239→      log.info(
240→        "Please edit it with your channel credentials (Telegram bot token, Discord bot token, etc.), then restart.",
241→      );
242→      process.exit(1);
243→    }
244→
245→    // 3. Read and parse
246→    const raw = JSON.parse(fs.readFileSync(this.configPath, "utf-8"));
247→
248→    // 3.5. Auto-migrate config
249→    const { changed: configUpdated } = applyMigrations(raw);
250→    if (configUpdated) {
251→      fs.writeFileSync(this.configPath, JSON.stringify(raw, null, 2));
252→    }
253→
254→    // 4. Apply env var overrides
255→    this.applyEnvOverrides(raw);
256→
257→    // 5. Validate with Zod
258→    const result = ConfigSchema.safeParse(raw);
259→    if (!result.success) {
260→      log.error("Config validation failed");
261→      for (const issue of result.error.issues) {
262→        log.error(
263→          { path: issue.path.join("."), message: issue.message },
264→          "Validation error",
265→        );
266→      }
267→      process.exit(1);
268→    }
269→    this.config = result.data;
270→  }
271→
272→  get(): Config {
273→    return this.config;
274→  }
275→
276→  async save(
277→    updates: Record<string, unknown>,
278→    changePath?: string,
279→  ): Promise<void> {
280→    const oldConfig = this.config ? structuredClone(this.config) : undefined;
281→    // Read current file, merge updates, write back
282→    const raw = JSON.parse(fs.readFileSync(this.configPath, "utf-8"));
283→    this.deepMerge(raw, updates);
284→    fs.writeFileSync(this.configPath, JSON.stringify(raw, null, 2));
285→    // Re-validate and update in-memory config
286→    const result = ConfigSchema.safeParse(raw);
287→    if (result.success) {
288→      this.config = result.data;
289→    }
290→    // Emit change event if path provided
291→    if (changePath) {
292→      const { getConfigValue } = await import("./config-registry.js");
293→      const value = getConfigValue(this.config, changePath);
294→      const oldValue = oldConfig
295→        ? getConfigValue(oldConfig, changePath)
296→        : undefined;
297→      this.emit("config:changed", { path: changePath, value, oldValue });
298→    }
299→  }
300→
301→  resolveWorkspace(input?: string): string {
302→    if (!input) {
303→      const resolved = expandHome(this.config.workspace.baseDir);
304→      fs.mkdirSync(resolved, { recursive: true });
305→      return resolved;
306→    }
307→    if (input.startsWith("/") || input.startsWith("~")) {
308→      const resolved = expandHome(input);
309→      fs.mkdirSync(resolved, { recursive: true });
310→      return resolved;
311→    }
312→    // Named workspace → lowercase, under baseDir
313→    const name = input.toLowerCase();
314→    const resolved = path.join(expandHome(this.config.workspace.baseDir), name);
315→    fs.mkdirSync(resolved, { recursive: true });
316→    return resolved;
317→  }
318→
319→  async exists(): Promise<boolean> {
320→    return fs.existsSync(this.configPath);
321→  }
322→
323→  getConfigPath(): string {
324→    return this.configPath;
325→  }
326→
327→  async writeNew(config: Config): Promise<void> {
328→    const dir = path.dirname(this.configPath);
329→    fs.mkdirSync(dir, { recursive: true });
330→    fs.writeFileSync(this.configPath, JSON.stringify(config, null, 2));
331→  }
332→
333→  private applyEnvOverrides(raw: Record<string, unknown>): void {
334→    const overrides: [string, string[]][] = [
335→      ["OPENACP_TELEGRAM_BOT_TOKEN", ["channels", "telegram", "botToken"]],
336→      ["OPENACP_TELEGRAM_CHAT_ID", ["channels", "telegram", "chatId"]],
337→      ["OPENACP_DISCORD_BOT_TOKEN", ["channels", "discord", "botToken"]],
338→      ["OPENACP_DISCORD_GUILD_ID", ["channels", "discord", "guildId"]],
339→      ["OPENACP_SLACK_BOT_TOKEN", ["channels", "slack", "botToken"]],
340→      ["OPENACP_SLACK_APP_TOKEN", ["channels", "slack", "appToken"]],
341→      ["OPENACP_SLACK_SIGNING_SECRET", ["channels", "slack", "signingSecret"]],
342→      ["OPENACP_DEFAULT_AGENT", ["defaultAgent"]],
343→      ["OPENACP_RUN_MODE", ["runMode"]],
344→      ["OPENACP_API_PORT", ["api", "port"]],
345→    ];
346→    for (const [envVar, configPath] of overrides) {
347→      const value = process.env[envVar];
348→      if (value !== undefined) {
349→        let target: Record<string, unknown> = raw;
350→        for (let i = 0; i < configPath.length - 1; i++) {
351→          if (!target[configPath[i]]) target[configPath[i]] = {};
352→          target = target[configPath[i]] as Record<string, unknown>;
353→        }
354→        const key = configPath[configPath.length - 1];
355→        // Convert numeric fields to number
356→        target[key] =
357→          key === "chatId" || key === "port" ? Number(value) : value;
358→      }
359→    }
360→
361→    // Logging env var overrides
362→    if (process.env.OPENACP_LOG_LEVEL) {
363→      raw.logging = raw.logging || {};
364→      (raw.logging as Record<string, unknown>).level =
365→        process.env.OPENACP_LOG_LEVEL;
366→    }
367→    if (process.env.OPENACP_LOG_DIR) {
368→      raw.logging = raw.logging || {};
369→      (raw.logging as Record<string, unknown>).logDir =
370→        process.env.OPENACP_LOG_DIR;
371→    }
372→    if (process.env.OPENACP_DEBUG && !process.env.OPENACP_LOG_LEVEL) {
373→      raw.logging = raw.logging || {};
374→      (raw.logging as Record<string, unknown>).level = "debug";
375→    }
376→
377→    // Tunnel env var overrides
378→    if (process.env.OPENACP_TUNNEL_ENABLED) {
379→      raw.tunnel = raw.tunnel || {};
380→      (raw.tunnel as Record<string, unknown>).enabled =
381→        process.env.OPENACP_TUNNEL_ENABLED === "true";
382→    }
383→    if (process.env.OPENACP_TUNNEL_PORT) {
384→      raw.tunnel = raw.tunnel || {};
385→      (raw.tunnel as Record<string, unknown>).port = Number(
386→        process.env.OPENACP_TUNNEL_PORT,
387→      );
388→    }
389→    if (process.env.OPENACP_TUNNEL_PROVIDER) {
390→      raw.tunnel = raw.tunnel || {};
391→      (raw.tunnel as Record<string, unknown>).provider =
392→        process.env.OPENACP_TUNNEL_PROVIDER;
393→    }
394→
395→    // Speech env var overrides
396→    if (process.env.OPENACP_SPEECH_STT_PROVIDER) {
397→      raw.speech = raw.speech || {};
398→      const speech = raw.speech as Record<string, unknown>;
399→      speech.stt = speech.stt || {};
400→      (speech.stt as Record<string, unknown>).provider =
401→        process.env.OPENACP_SPEECH_STT_PROVIDER;
402→    }
403→    if (process.env.OPENACP_SPEECH_GROQ_API_KEY) {
404→      raw.speech = raw.speech || {};
405→      const speech = raw.speech as Record<string, unknown>;
406→      speech.stt = speech.stt || {};
407→      const stt = speech.stt as Record<string, unknown>;
408→      stt.providers = stt.providers || {};
409→      const providers = stt.providers as Record<string, unknown>;
410→      providers.groq = providers.groq || {};
411→      (providers.groq as Record<string, unknown>).apiKey =
412→        process.env.OPENACP_SPEECH_GROQ_API_KEY;
413→    }
414→  }
415→
416→  private deepMerge(
417→    target: Record<string, unknown>,
418→    source: Record<string, unknown>,
419→  ): void {
420→    for (const key of Object.keys(source)) {
421→      const val = source[key];
422→      if (val && typeof val === "object" && !Array.isArray(val)) {
423→        if (!target[key]) target[key] = {};
424→        this.deepMerge(
425→          target[key] as Record<string, unknown>,
426→          val as Record<string, unknown>,
427→        );
428→      } else {
429→        target[key] = val;
430→      }
431→    }
432→  }
433→}
