 23→export class ToolCallTracker {
 24→  private sessions: Map<string, Map<string, ToolCallState>> = new Map();
 25→
 26→  constructor(
 27→    private bot: Bot,
 28→    private chatId: number,
 29→    private sendQueue: TelegramSendQueue,
 30→  ) {}
 31→
 32→  async trackNewCall(
 33→    sessionId: string,
 34→    threadId: number,
 35→    meta: ToolCallMeta,
 36→    verbosity: DisplayVerbosity = "medium",
 37→  ): Promise<void> {
 38→    if (!this.sessions.has(sessionId)) {
 39→      this.sessions.set(sessionId, new Map());
 40→    }
 41→
 42→    let resolveReady!: () => void;
 43→    const ready = new Promise<void>((r) => {
 44→      resolveReady = r;
 45→    });
 46→
 47→    this.sessions.get(sessionId)!.set(meta.id, {
 48→      msgId: 0,
 49→      name: meta.name,
 50→      kind: meta.kind,
 51→      rawInput: meta.rawInput,
 52→      viewerLinks: meta.viewerLinks,
 53→      viewerFilePath: meta.viewerFilePath,
 54→      ready,
 55→    });
 56→
 57→    try {
 58→      const msg = await this.sendQueue.enqueue(() =>
 59→        this.bot.api.sendMessage(this.chatId, formatToolCall(meta, verbosity), {
 60→          message_thread_id: threadId,
 61→          parse_mode: "HTML",
 62→          disable_notification: true,
 63→        }),
 64→      );
 65→
 66→      const toolEntry = this.sessions.get(sessionId)!.get(meta.id)!;
 67→      toolEntry.msgId = msg!.message_id;
 68→    } finally {
 69→      resolveReady();
 70→    }
 71→  }
 72→
 73→  async updateCall(
 74→    sessionId: string,
 75→    meta: ToolCallMeta & { status: string },
 76→    verbosity: DisplayVerbosity = "medium",
 77→  ): Promise<void> {
 78→    const toolState = this.sessions.get(sessionId)?.get(meta.id);
 79→    if (!toolState) return;
 80→
 81→    // Accumulate state from intermediate updates
 82→    if (meta.viewerLinks) {
 83→      toolState.viewerLinks = meta.viewerLinks;
 84→      log.debug(
 85→        { toolId: meta.id, viewerLinks: meta.viewerLinks },
 86→        "Accumulated viewerLinks",
 87→      );
 88→    }
 89→    if (meta.viewerFilePath) toolState.viewerFilePath = meta.viewerFilePath;
 90→    if (meta.name) toolState.name = meta.name;
 91→    if (meta.kind) toolState.kind = meta.kind;
 92→
 93→    // Only edit on terminal status — minimizes API calls to avoid rate limits
 94→    const TERMINAL_STATUSES = new Set([
 95→      "completed",
 96→      "failed",
 97→      "done",
 98→      "error",
 99→      "cancelled",
100→    ]);
101→    if (!TERMINAL_STATUSES.has(meta.status)) return;
102→
103→    await toolState.ready;
104→
105→    log.debug(
106→      {
107→        toolId: meta.id,
108→        status: meta.status,
109→        hasViewerLinks: !!toolState.viewerLinks,
110→        viewerLinks: toolState.viewerLinks,
111→        name: toolState.name,
112→        msgId: toolState.msgId,
113→      },
114→      "Tool completed, preparing edit",
115→    );
116→
117→    const merged = {
118→      ...meta,
119→      name: toolState.name,
120→      kind: toolState.kind,
121→      rawInput: toolState.rawInput,
122→      viewerLinks: toolState.viewerLinks,
123→      viewerFilePath: toolState.viewerFilePath,
124→    };
125→    const formattedText = formatToolUpdate(merged, verbosity);
126→
127→    try {
128→      await this.sendQueue.enqueue(() =>
129→        this.bot.api.editMessageText(
130→          this.chatId,
131→          toolState.msgId,
132→          formattedText,
133→          { parse_mode: "HTML" },
134→        ),
135→      );
136→    } catch (err) {
137→      log.warn(
138→        {
139→          err,
140→          msgId: toolState.msgId,
141→          textLen: formattedText.length,
142→          hasViewerLinks: !!merged.viewerLinks,
143→        },
144→        "Tool update edit failed",
145→      );
146→    }
147→  }
148→
149→  cleanup(sessionId: string): void {
150→    this.sessions.delete(sessionId);
151→  }
152→}
