 82→export function formatToolCall(
 83→  tool: ToolCallMeta,
 84→  verbosity: DisplayVerbosity = "medium",
 85→): string {
 86→  const si = STATUS_ICONS[tool.status || ""] || "🔧";
 87→  const name = tool.name || "Tool";
 88→  const label =
 89→    verbosity === "low"
 90→      ? formatToolTitle(name, tool.rawInput)
 91→      : formatToolSummary(name, tool.rawInput);
 92→  let text = `${si} <b>${escapeHtml(label)}</b>`;
 93→  text += formatViewerLinks(tool.viewerLinks, tool.viewerFilePath);
 94→  // high: always show content; medium: show when no viewer links; low: never
 95→  if (verbosity === "high" || (verbosity === "medium" && !tool.viewerLinks)) {
 96→    const details = stripCodeFences(extractContentText(tool.content));
 97→    if (details) {
 98→      text += `\n<pre>${escapeHtml(truncateContent(details, 3800))}</pre>`;
 99→    }
100→  }
101→  return text;
102→}
