125→function formatViewerLinks(links?: ViewerLinks, filePath?: string): string {
126→  if (!links) return "";
127→  const fileName = filePath ? filePath.split("/").pop() || filePath : "";
128→  let text = "\n";
129→  if (links.file)
130→    text += `\n📄 <a href="${escapeHtml(links.file)}">View ${escapeHtml(fileName || "file")}</a>`;
131→  if (links.diff)
132→    text += `\n📝 <a href="${escapeHtml(links.diff)}">View diff${fileName ? ` — ${escapeHtml(fileName)}` : ""}</a>`;
133→  return text;
134→}
