136→export function formatPlan(plan: {
137→  entries: Array<{ content: string; status: string }>;
138→}): string {
139→  const statusIcon: Record<string, string> = {
140→    pending: "⬜",
141→    in_progress: "🔄",
142→    completed: "✅",
143→  };
144→  const lines = plan.entries.map(
145→    (e, i) =>
146→      `${statusIcon[e.status] || "⬜"} ${i + 1}. ${escapeHtml(e.content)}`,
147→  );
