151→export function formatUsage(usage: {
152→  tokensUsed?: number;
153→  contextSize?: number;
154→}): string {
155→  const { tokensUsed, contextSize } = usage;
156→  if (tokensUsed == null) return "📊 Usage data unavailable";
157→  if (contextSize == null) return `📊 ${formatTokens(tokensUsed)} tokens`;
158→
159→  const ratio = tokensUsed / contextSize;
160→  const pct = Math.round(ratio * 100);
161→  const bar = progressBar(ratio);
162→  const emoji = pct >= 85 ? "⚠️" : "📊";
163→  return `${emoji} ${formatTokens(tokensUsed)} / ${formatTokens(contextSize)} tokens\n${bar} ${pct}%`;
164→}
