177→    used: number;
178→    budget: number;
179→    percent: number;
180→  },
181→): string {
182→  const hasData = summaries.some((s) => s.recordCount > 0);
183→  if (!hasData) {
184→    return "📊 <b>Usage Report</b>\n\nNo usage data yet.";
185→  }
186→
187→  const formatCost = (n: number) => `$${n.toFixed(2)}`;
188→  const lines: string[] = ["📊 <b>Usage Report</b>"];
189→
190→  for (const summary of summaries) {
191→    lines.push("");
192→    lines.push(
193→      `── <b>${PERIOD_LABEL[summary.period] ?? summary.period}</b> ──`,
194→    );
195→    lines.push(
196→      `💰 ${formatCost(summary.totalCost)} · 🔤 ${formatTokens(summary.totalTokens)} tokens · 📋 ${summary.sessionCount} sessions`,
197→    );
198→
199→    // Show budget bar only on the month section
200→    if (summary.period === "month" && budgetStatus.budget > 0) {
201→      const bar = progressBar(budgetStatus.used / budgetStatus.budget);
202→      lines.push(
203→        `Budget: ${formatCost(budgetStatus.used)} / ${formatCost(budgetStatus.budget)} (${budgetStatus.percent}%)`,
204→      );
205→      lines.push(`${bar} ${budgetStatus.percent}%`);
206→    }
207→  }
208→
209→  return lines.join("\n");
210→}
