 11→  transform(
 12→    event: AgentEvent,
 13→    sessionContext?: { id: string; workingDirectory: string },
 14→  ): OutgoingMessage {
 15→    switch (event.type) {
 16→      case "text":
 17→        return { type: "text", text: event.content };
 18→      case "thought":
 19→        return { type: "thought", text: event.content };
 20→      case "tool_call": {
 21→        const meta = event.meta as Record<string, unknown> | undefined;
 22→        const metadata: Record<string, unknown> = {
 23→          id: event.id,
 24→          name: event.name,
 25→          kind: event.kind,
 26→          status: event.status,
 27→          content: event.content,
 28→          locations: event.locations,
 29→          rawInput: event.rawInput,
 30→          displaySummary: meta?.displaySummary,
 31→          displayTitle: meta?.displayTitle,
 32→          displayKind: meta?.displayKind,
 33→        };
 34→        this.enrichWithViewerLinks(event, metadata, sessionContext);
 35→        return { type: "tool_call", text: event.name, metadata };
 36→      }
 37→      case "tool_update": {
 38→        const meta = event.meta as Record<string, unknown> | undefined;
 39→        const metadata: Record<string, unknown> = {
 40→          id: event.id,
 41→          name: event.name,
 42→          kind: event.kind,
 43→          status: event.status,
 44→          content: event.content,
 45→          rawInput: event.rawInput,
 46→          displaySummary: meta?.displaySummary,
 47→          displayTitle: meta?.displayTitle,
 48→          displayKind: meta?.displayKind,
 49→        };
 50→        this.enrichWithViewerLinks(event, metadata, sessionContext);
 51→        return { type: "tool_update", text: "", metadata };
 52→      }
 53→      case "plan":
 54→        return {
 55→          type: "plan",
 56→          text: "",
 57→          metadata: { entries: event.entries },
 58→        };
 59→      case "usage":
 60→        return {
 61→          type: "usage",
 62→          text: "",
 63→          metadata: {
 64→            tokensUsed: event.tokensUsed,
 65→            contextSize: event.contextSize,
 66→            cost: event.cost,
 67→          },
 68→        };
 69→      case "session_end":
 70→        return { type: "session_end", text: `Done (${event.reason})` };
 71→      case "error":
 72→        return { type: "error", text: event.message };
 73→      case "system_message":
 74→        return { type: "system_message", text: event.message };
 75→      default:
 76→        return { type: "text", text: "" };
 77→    }
 78→  }
 79→
 80→  private enrichWithViewerLinks(
 81→    event: AgentEvent & { type: "tool_call" | "tool_update" },
 82→    metadata: Record<string, unknown>,
 83→    sessionContext?: { id: string; workingDirectory: string },
 84→  ): void {
 85→    if (!this.tunnelService || !sessionContext) return;
 86→
 87→    const name = "name" in event ? event.name || "" : "";
 88→    const kind = "kind" in event ? event.kind : undefined;
 89→
 90→    log.debug(
 91→      { name, kind, status: event.status, hasContent: !!event.content },
 92→      "enrichWithViewerLinks: inspecting event",
 93→    );
 94→
 95→    const fileInfo = extractFileInfo(
 96→      name,
 97→      kind,
 98→      event.content,
 99→      event.rawInput,
100→      event.meta,
101→    );
102→    if (!fileInfo) return;
103→
104→    log.info(
105→      {
106→        name,
107→        kind,
108→        filePath: fileInfo.filePath,
109→        hasOldContent: !!fileInfo.oldContent,
110→      },
111→      "enrichWithViewerLinks: extracted file info",
112→    );
113→
114→    const store = this.tunnelService.getStore();
115→    const viewerLinks: Record<string, string> = {};
116→
117→    // For edits/writes with diff data (oldText + newText)
118→    if (fileInfo.oldContent) {
119→      const id = store.storeDiff(
120→        sessionContext.id,
121→        fileInfo.filePath,
122→        fileInfo.oldContent,
123→        fileInfo.content,
124→        sessionContext.workingDirectory,
125→      );
126→      if (id) viewerLinks.diff = this.tunnelService.diffUrl(id);
127→    }
128→
129→    // Always store as file view (new file creation or read)
130→    const id = store.storeFile(
131→      sessionContext.id,
132→      fileInfo.filePath,
133→      fileInfo.content,
134→      sessionContext.workingDirectory,
135→    );
136→    if (id) viewerLinks.file = this.tunnelService.fileUrl(id);
137→
138→    if (Object.keys(viewerLinks).length > 0) {
139→      metadata.viewerLinks = viewerLinks;
140→      metadata.viewerFilePath = fileInfo.filePath;
141→    }
142→  }
143→}
