 21→export class ToolCallTracker {
 22→  sessions: Map<string, Map<string, ToolCallState>> = new Map();
 23→
 24→  constructor(private sendQueue: DiscordSendQueue) {}
 25→
 26→  async trackNewCall(
 27→    sessionId: string,
 28→    thread: TextChannel | ThreadChannel,
 29→    tool: ToolCallMeta,
 30→    verbosity: DisplayVerbosity = "medium",
 31→  ): Promise<void> {
 32→    if (!this.sessions.has(sessionId)) {
 33→      this.sessions.set(sessionId, new Map());
 34→    }
 35→
 36→    let resolveReady!: () => void;
 37→    const ready = new Promise<void>((r) => {
 38→      resolveReady = r;
 39→    });
 40→
 41→    const state: ToolCallState = {
 42→      message: undefined,
 43→      name: tool.name,
 44→      kind: tool.kind,
 45→      rawInput: tool.rawInput,
 46→      viewerLinks: tool.viewerLinks,
 47→      viewerFilePath: tool.viewerFilePath,
 48→      ready,
 49→    };
 50→
 51→    this.sessions.get(sessionId)!.set(tool.id, state);
 52→
 53→    const content = formatToolCall(tool, verbosity);
 54→
 55→    try {
 56→      const msg = await this.sendQueue.enqueue(() => thread.send({ content }), {
 57→        type: "other",
 58→      });
 59→      if (msg) state.message = msg;
 60→    } catch (err) {
 61→      log.warn(
 62→        { err, toolId: tool.id },
 63→        "[ToolCallTracker] trackNewCall() send failed",
 64→      );
 65→    } finally {
 66→      resolveReady();
 67→    }
 68→  }
 69→
 70→  async updateCall(
 71→    sessionId: string,
 72→    update: ToolCallMeta & { status: string },
 73→    verbosity: DisplayVerbosity = "medium",
 74→  ): Promise<void> {
 75→    const toolState = this.sessions.get(sessionId)?.get(update.id);
 76→    if (!toolState) return;
 77→
 78→    // Accumulate fields from intermediate updates
 79→    if (update.viewerLinks) toolState.viewerLinks = update.viewerLinks;
 80→    if (update.viewerFilePath) toolState.viewerFilePath = update.viewerFilePath;
 81→    if (update.name) toolState.name = update.name;
 82→    if (update.kind) toolState.kind = update.kind;
 83→
 84→    // Only edit on terminal status — minimizes API calls to avoid rate limits
 85→    const TERMINAL_STATUSES = new Set([
 86→      "completed",
 87→      "failed",
 88→      "done",
 89→      "error",
 90→      "cancelled",
 91→    ]);
 92→    if (!TERMINAL_STATUSES.has(update.status)) return;
 93→
 94→    // Wait for initial send to complete before editing
 95→    await toolState.ready;
 96→
 97→    if (!toolState.message) return;
 98→
 99→    log.debug(
100→      {
101→        toolId: update.id,
102→        status: update.status,
103→        hasViewerLinks: !!toolState.viewerLinks,
104→        name: toolState.name,
105→        msgId: toolState.message.id,
106→      },
107→      "[ToolCallTracker] Tool completed, preparing edit",
108→    );
109→
110→    const merged = {
111→      ...update,
112→      name: toolState.name,
113→      kind: toolState.kind,
114→      rawInput: toolState.rawInput,
115→      viewerLinks: toolState.viewerLinks,
116→      viewerFilePath: toolState.viewerFilePath,
117→    };
118→    const content = formatToolUpdate(merged, verbosity);
119→
120→    try {
121→      await this.sendQueue.enqueue(() => toolState.message!.edit({ content }), {
122→        type: "other",
123→      });
124→    } catch (err) {
125→      log.warn(
126→        {
127→          err,
128→          msgId: toolState.message.id,
129→          contentLen: content.length,
130→          hasViewerLinks: !!merged.viewerLinks,
131→        },
132→        "[ToolCallTracker] Tool update edit failed",
133→      );
134→    }
135→  }
136→
137→  cleanup(sessionId: string): void {
138→    this.sessions.delete(sessionId);
139→  }
140→}
