 21→
 22→export function escapeHtml(text: string | undefined | null): string {
 23→  if (!text) return "";
 24→  return text
 25→    .replace(/&/g, "&amp;")
 26→    .replace(/</g, "&lt;")
 27→    .replace(/>/g, "&gt;");
 28→}
 29→
 30→export function markdownToTelegramHtml(md: string): string {
 31→  // Step 1: Extract code blocks and inline code into placeholders
 32→  const codeBlocks: string[] = [];
 33→  const inlineCodes: string[] = [];
 34→
 35→  // Extract fenced code blocks (```lang\n...\n```)
 36→  let text = md.replace(
 37→    /```(\w*)\n?([\s\S]*?)```/g,
 38→    (_match, lang: string, code: string) => {
 39→      const index = codeBlocks.length;
 40→      const escapedCode = escapeHtml(code);
 41→      const langAttr = lang ? ` class="language-${escapeHtml(lang)}"` : "";
 42→      codeBlocks.push(`<pre><code${langAttr}>${escapedCode}</code></pre>`);
 43→      return `\x00CODE_BLOCK_${index}\x00`;
 44→    },
 45→  );
 46→
 47→  // Extract inline code (`...`)
 48→  text = text.replace(/`([^`]+)`/g, (_match, code: string) => {
 49→    const index = inlineCodes.length;
 50→    inlineCodes.push(`<code>${escapeHtml(code)}</code>`);
 51→    return `\x00INLINE_CODE_${index}\x00`;
 52→  });
 53→
 54→  // Step 2: Escape HTML in remaining text
 55→  text = escapeHtml(text);
 56→
 57→  // Step 3: Apply markdown transformations
 58→  // Bold: **text** → <b>text</b>
 59→  text = text.replace(/\*\*(.+?)\*\*/g, "<b>$1</b>");
 60→
 61→  // Italic: *text* → <i>text</i> (but not the ** used for bold)
 62→  text = text.replace(/(?<!\*)\*(?!\*)(.+?)(?<!\*)\*(?!\*)/g, "<i>$1</i>");
 63→
 64→  // Links: [text](url) → <a href="url">text</a>
 65→  // Note: after escapeHtml, parentheses are not affected, but we need to handle
 66→  // the escaped brackets properly. Since [ ] and ( ) are not escaped, this works directly.
 67→  text = text.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2">$1</a>');
 68→
 69→  // Step 4: Restore fenced code blocks
 70→  text = text.replace(/\x00CODE_BLOCK_(\d+)\x00/g, (_match, idx: string) => {
 71→    return codeBlocks[parseInt(idx, 10)];
 72→  });
 73→
 74→  // Step 5: Restore inline code
 75→  text = text.replace(/\x00INLINE_CODE_(\d+)\x00/g, (_match, idx: string) => {
 76→    return inlineCodes[parseInt(idx, 10)];
 77→  });
 78→
 79→  return text;
 80→}
 81→
 82→export function formatToolCall(
 83→  tool: ToolCallMeta,
